app.get("/sw.js", (req, res) => {
  res.setHeader("Content-Type", "application/javascript; charset=utf-8");
  res.setHeader("Cache-Control", "no-store");

  res.send(`
const CACHE_NAME = "iqg-dashboard-pwa-v1";
const STATIC_ASSETS = [
  "/iqg-icon.svg"
];

self.addEventListener("install", event => {
  self.skipWaiting();

  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => cache.addAll(STATIC_ASSETS))
      .catch(() => null)
  );
});

self.addEventListener("activate", event => {
  event.waitUntil(
    caches.keys()
      .then(keys => Promise.all(
        keys
          .filter(key => key !== CACHE_NAME)
          .map(key => caches.delete(key))
      ))
      .then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", event => {
  const requestUrl = new URL(event.request.url);

  // Não cachear dashboard, leads, rotas POST, APIs ou dados sensíveis.
  if (
    event.request.method !== "GET" ||
    requestUrl.pathname.startsWith("/dashboard") ||
    requestUrl.pathname.startsWith("/lead/") ||
    requestUrl.pathname.startsWith("/conversation/") ||
    requestUrl.pathname.startsWith("/webhook")
  ) {
    return;
  }

  if (requestUrl.pathname === "/iqg-icon.svg") {
    event.respondWith(
      caches.match(event.request).then(cached => {
        return cached || fetch(event.request);
      })
    );
  }
});
`);
});

const client = new MongoClient(process.env.MONGODB_URI);
let db;

/* =========================
   🔥 MONGODB (CORRIGIDO)
========================= */

async function connectMongo() {
  try {
    if (!db) {
      await client.connect();
      db = client.db("iqg");
      console.log("🔥 Mongo conectado");
      return;
    }

    await db.command({ ping: 1 });
  } catch (error) {
    console.error("⚠️ Mongo desconectado. Tentando reconectar...", error.message);

    try {
      await client.close().catch(() => {});
      await client.connect();
      db = client.db("iqg");
      console.log("🔥 Mongo reconectado");
    } catch (reconnectError) {
      console.error("❌ Falha ao reconectar Mongo:", reconnectError);
      throw reconnectError;
    }
  }
}

// ============================================================
// fetchWithTimeout — Bug #3: proteção contra hang indefinido
// ============================================================
// Todos os fetch externos devem usar fetchWithTimeout com timeout
// adequado por categoria de endpoint.
// Em caso de timeout, throw Error("fetch_timeout_<ms>ms: <url>")
// ============================================================
const FETCH_TIMEOUTS = {
  OPENAI_CHAT: 60000,
  OPENAI_AUDIO: 90000,
  WHATSAPP: 15000,
  MEDIA_DOWNLOAD: 45000,
  DEFAULT: 30000
};

async function fetchWithTimeout(url, options = {}, timeoutMs = FETCH_TIMEOUTS.DEFAULT) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(url, { ...options, signal: controller.signal });
    return response;
  } catch (err) {
    if (err && err.name === "AbortError") {
      const urlPreview = typeof url === "string"
        ? url.slice(0, 100)
        : String(url).slice(0, 100);
      const timeoutErr = new Error(`fetch_timeout_${timeoutMs}ms: ${urlPreview}`);
      timeoutErr.code = "FETCH_TIMEOUT";
      timeoutErr.originalUrl = urlPreview;
      timeoutErr.timeoutMs = timeoutMs;
      throw timeoutErr;
    }
    throw err;
  } finally {
    clearTimeout(timeoutId);
  }
}

// ============================================================
// fetchOpenAIWithRetry — Bug #4: retry com backoff exponential
// + circuit breaker + Retry-After RFC 7231 + jitter ±20%
// ============================================================
// Signature drop-in: fetchOpenAIWithRetry(url, options)
// Timeout interno baseado em URL (chat vs audio).
// Throw Error estruturado com code/openaiStatus/attempts pra Bug #6.
// ============================================================

const OPENAI_RETRY = {
  maxAttempts: 3,
  baseDelayMs: 1000,
  maxDelayMs: 30000,
  retryableStatus: [408, 425, 429, 500, 502, 503, 504]
};

const OPENAI_CIRCUIT = {
  failures: 0,
  openedAt: 0,
  threshold: 10,
  cooldownMs: 60 * 1000
};

function parseRetryAfter(headerValue) {
  if (!headerValue) return null;
  const asNumber = parseInt(headerValue, 10);
  if (!isNaN(asNumber)) {
    if (asNumber < 0) return null;
    if (asNumber === 0) return 100;
    return asNumber * 1000;
  }
  const asDate = Date.parse(headerValue);
  if (!isNaN(asDate)) {
    const diff = asDate - Date.now();
    return Math.max(100, diff);
  }
  return null;
}

async function fetchOpenAIWithRetry(url, options = {}) {
  const startTime = Date.now();

  const timeoutMs = (typeof url === "string" && url.includes("/audio/"))
    ? FETCH_TIMEOUTS.OPENAI_AUDIO
    : FETCH_TIMEOUTS.OPENAI_CHAT;

  if (OPENAI_CIRCUIT.openedAt > 0 &&
      Date.now() - OPENAI_CIRCUIT.openedAt < OPENAI_CIRCUIT.cooldownMs) {
    const err = new Error("OpenAI circuit open — cooldown ativo");
    err.code = "OPENAI_CIRCUIT_OPEN";
    err.openaiStatus = null;
    err.openaiBody = null;
    err.attempts = 0;
    err.durationMs = Date.now() - startTime;
    throw err;
  }
  if (OPENAI_CIRCUIT.openedAt > 0 &&
      Date.now() - OPENAI_CIRCUIT.openedAt >= OPENAI_CIRCUIT.cooldownMs) {
    OPENAI_CIRCUIT.openedAt = 0;
    OPENAI_CIRCUIT.failures = 0;
    auditSystemEvent("openai_circuit_half_open_test", "low", null, {
      cooldownMs: OPENAI_CIRCUIT.cooldownMs
    }).catch(() => {});
  }

  let lastResponse = null;
  let lastBody = null;
  let lastErr = null;

  for (let attempt = 1; attempt <= OPENAI_RETRY.maxAttempts; attempt++) {
    try {
      const response = await fetchWithTimeout(url, options, timeoutMs);
      lastResponse = response;

      if (response.ok) {
        if (OPENAI_CIRCUIT.failures > 0) {
          auditSystemEvent("openai_circuit_closed_recovered", "low", null, {
            previousFailures: OPENAI_CIRCUIT.failures
          }).catch(() => {});
        }
        OPENAI_CIRCUIT.failures = 0;
        OPENAI_CIRCUIT.openedAt = 0;
        return response;
      }

      if (!OPENAI_RETRY.retryableStatus.includes(response.status)) {
        return response;
      }

      try {
        lastBody = await response.clone().text();
      } catch (_) { lastBody = null; }

      const retryAfterHeader = response.headers.get("retry-after");
      const retryAfterMs = parseRetryAfter(retryAfterHeader);

      let delay;
      if (retryAfterMs !== null) {
        if (retryAfterMs > OPENAI_RETRY.maxDelayMs) {
          OPENAI_CIRCUIT.openedAt = Date.now();
          await auditSystemEvent("openai_circuit_opened_long_retry_after", "high", null, {
            retryAfterMs,
            status: response.status,
            url: typeof url === "string" ? url.slice(0, 80) : "unknown"
          }).catch(() => {});
          const err = new Error(`OpenAI Retry-After excessivo: ${retryAfterMs}ms`);
          err.code = "OPENAI_LONG_RETRY_AFTER";
          err.openaiStatus = response.status;
          err.openaiBody = lastBody?.slice(0, 500) || null;
          err.attempts = attempt;
          err.durationMs = Date.now() - startTime;
          throw err;
        }
        delay = retryAfterMs;
      } else {
        delay = Math.min(
          OPENAI_RETRY.baseDelayMs * Math.pow(2, attempt - 1),
          OPENAI_RETRY.maxDelayMs
        );
      }

      delay = Math.floor(delay * (0.8 + Math.random() * 0.4));

      console.warn(`OpenAI ${response.status} attempt ${attempt}/${OPENAI_RETRY.maxAttempts}, delay=${delay}ms`);

      if (attempt < OPENAI_RETRY.maxAttempts) {
        await new Promise(r => setTimeout(r, delay));
      }
    } catch (err) {
      lastErr = err;
      if (err.code === "OPENAI_LONG_RETRY_AFTER") throw err;
      if (err.code === "OPENAI_CIRCUIT_OPEN") throw err;

      const delay = Math.floor(
        OPENAI_RETRY.baseDelayMs * Math.pow(2, attempt - 1) * (0.8 + Math.random() * 0.4)
      );
      console.warn(`OpenAI ${err.name || "error"} attempt ${attempt}/${OPENAI_RETRY.maxAttempts}: ${err.message?.slice(0, 100)}, delay=${delay}ms`);

      if (attempt < OPENAI_RETRY.maxAttempts) {
        await new Promise(r => setTimeout(r, delay));
      }
    }
  }

  OPENAI_CIRCUIT.failures++;
  if (OPENAI_CIRCUIT.failures >= OPENAI_CIRCUIT.threshold) {
    OPENAI_CIRCUIT.openedAt = Date.now();
    await auditSystemEvent("openai_circuit_opened", "critical", null, {
      failures: OPENAI_CIRCUIT.failures,
      threshold: OPENAI_CIRCUIT.threshold,
      cooldownMs: OPENAI_CIRCUIT.cooldownMs
    }).catch(() => {});
  }

  const err = lastErr || new Error(`OpenAI esgotou ${OPENAI_RETRY.maxAttempts} tentativas`);
  err.code = err.code || "OPENAI_RETRY_EXHAUSTED";
  err.openaiStatus = lastResponse?.status || null;
  err.openaiBody = lastBody?.slice(0, 500) || null;
  err.attempts = OPENAI_RETRY.maxAttempts;
  err.durationMs = Date.now() - startTime;
  throw err;
}

// ============================================================
// verifyMetaSignature — Bug #2: valida HMAC SHA-256 do webhook Meta
// ============================================================
// Meta WhatsApp Cloud API assina cada POST com X-Hub-Signature-256.
// Retorna { valid, reason, warn? } pra caller decidir ação por modo.
//
// Modos via env HMAC_ENFORCEMENT:
//   strict (default) — rejeita inválido
//   warn-only        — loga mas passa
//   off              — desliga
//
// Secret ausente → pass-through + audit critical (NUNCA derruba SDR).
// ============================================================
function verifyMetaSignature(req) {
  const enforcement = (process.env.HMAC_ENFORCEMENT || "strict").toLowerCase();

  if (enforcement === "off") {
    return { valid: true, reason: "enforcement_off" };
  }

  const secret = (process.env.WHATSAPP_APP_SECRET || "").trim();

  if (!secret) {
    return { valid: true, reason: "secret_missing", warn: true };
  }

  const signatureHeader = req.headers["x-hub-signature-256"];

  if (!signatureHeader) {
    return { valid: false, reason: "header_missing" };
  }

  if (!req.rawBody) {
    return { valid: false, reason: "rawbody_missing" };
  }

  let expected;
  try {
    // NOTA: Meta WhatsApp sempre envia X-Hub-Signature-256 em lowercase hex.
    // Comparação case-sensitive POR DESIGN. Se Meta mudar policy, normalizar
    // com .toLowerCase() ANTES do Buffer.from() (mantendo timing-safe).
    expected = "sha256=" + crypto
      .createHmac("sha256", secret)
      .update(req.rawBody)
      .digest("hex");
  } catch (hmacErr) {
    return { valid: false, reason: "compute_error", error: hmacErr.message };
  }

  const sigBuf = Buffer.from(signatureHeader);
  const expBuf = Buffer.from(expected);

  if (sigBuf.length !== expBuf.length) {
    return { valid: false, reason: "length_mismatch" };
  }

  let match;
  try {
    match = crypto.timingSafeEqual(sigBuf, expBuf);
  } catch (cmpErr) {
    return { valid: false, reason: "compare_error", error: cmpErr.message };
  }

  return { valid: match, reason: match ? "valid" : "signature_mismatch" };
}

// ============================================================
// classifyError — Bug #6: categoriza erro em vez de hardcode
// ============================================================
// Cobre AMBOS domínios:
//   - OpenAI: err.code OPENAI_* (Bug #4) + openaiStatus
//   - WhatsApp/fetch: FETCH_TIMEOUT (Bug #3) + HTTP status Meta
//   - Erros tipados (ReferenceError, TypeError)
//   - Fallback por mensagem (legado)
// Retorna objeto estruturado pro caller injetar no payload do audit.
// PRESERVA eventType do caller — só enriquece payload.classification.
// ============================================================
function classifyError(err, response = null) {
  const code = err?.code || null;
  const httpStatus = err?.openaiStatus ?? response?.status ?? null;
  const message = (err?.message || "").slice(0, 200);
  const url = err?.originalUrl || "";

  let kind = "unknown";
  let retryable = false;

  if (code === "OPENAI_CIRCUIT_OPEN") {
    kind = "openai_circuit"; retryable = false;
  } else if (code === "OPENAI_LONG_RETRY_AFTER") {
    kind = "openai_rate_limit_excessive"; retryable = false;
  } else if (code === "OPENAI_RETRY_EXHAUSTED") {
    kind = "openai_exhausted_retries"; retryable = false;
  } else if (code === "FETCH_TIMEOUT") {
    if (url.includes("openai.com")) kind = "openai_timeout";
    else if (url.includes("graph.facebook")) kind = "whatsapp_timeout";
    else kind = "external_timeout";
    retryable = true;
  }
  else if (httpStatus === 401) { kind = "unauthorized"; retryable = false; }
  else if (httpStatus === 403) { kind = "forbidden"; retryable = false; }
  else if (httpStatus === 429) { kind = "rate_limited"; retryable = true; }
  else if (httpStatus >= 500 && httpStatus < 600) { kind = "server_5xx"; retryable = true; }
  else if (httpStatus >= 400 && httpStatus < 500) { kind = "client_4xx"; retryable = false; }
  else if (err?.name === "ReferenceError") { kind = "code_reference_error"; retryable = false; }
  else if (err?.name === "TypeError") { kind = "code_type_error"; retryable = false; }
  else if (/falha ao enviar mensagem whatsapp|whatsapp/i.test(message)) {
    kind = "whatsapp_send_failed"; retryable = true;
  } else if (/falha ao chamar openai/i.test(message)) {
    kind = "openai_failed_legacy"; retryable = true;
  } else if (/econnrefused|enotfound|etimedout|socket hang up|network|fetch failed/i.test(message)) {
    kind = "network"; retryable = true;
  }

  return {
    kind,
    code,
    httpStatus,
    retryable,
    attempts: err?.attempts ?? null,
    durationMs: err?.durationMs ?? null,
    message,
    originalUrl: url || null
  };
}

// Bug #1 — rate limit de cadência (anti-ban WhatsApp)
const RATE_LIMIT_QUERY_TIMEOUT_MS = 3000;
const MAX_SDR_MSGS_24H = parseInt(process.env.MAX_SDR_MSGS_24H || "10", 10);

// ============================================================
// isCountableSdrMessage — Bug #1 / Gap #1: msg SDR que conta
// pro rate limit. Exclui content vazio e mensagens que são
// SÓ tags [ACTION:...] (sem texto real pro lead).
// Conta QUALQUER role:"assistant" real — followup OU resposta IA
// (rajada de qualquer fonte é risco de ban).
// ============================================================
function isCountableSdrMessage(m) {
  if (!m || m.role !== "assistant") return false;
  if (!m.createdAt) return false;
  const content = String(m.content || "");
  if (content.trim().length === 0) return false;
  const withoutActions = content.replace(/\[ACTION:[^\]]+\]/g, "").trim();
  if (withoutActions.length === 0) return false;
  return true;
}

// ============================================================
// getRecentSdrStats — Bug #1: conta msgs SDR de um lead nas
// últimas windowMs. Query com timeout fail-open (Mongo lento
// não derruba cadência). Retorna { count, timeoutFallback }.
// ============================================================
async function getRecentSdrStats(user, windowMs = 24 * 60 * 60 * 1000) {
  const queryPromise = db.collection("conversations").findOne(
    { user },
    { projection: { messages: { $slice: -100 } } }
  );
  const timeoutPromise = new Promise((_, reject) =>
    setTimeout(() => reject(new Error("rate_limit_query_timeout")), RATE_LIMIT_QUERY_TIMEOUT_MS)
  );

  let conv;
  try {
    conv = await Promise.race([queryPromise, timeoutPromise]);
  } catch (err) {
    return { count: 0, timeoutFallback: true };
  }

  const allMsgs = conv?.messages || [];
  const now = Date.now();
  const windowStart = now - windowMs;

  const count = allMsgs.filter(m =>
    isCountableSdrMessage(m) &&
    new Date(m.createdAt).getTime() >= windowStart
  ).length;

  return { count, timeoutFallback: false };
}

async function claimMessage(messageId) {
  if (!messageId) return true;

  await connectMongo();

  try {
    await db.collection("processed_messages").insertOne({
      _id: messageId,
      createdAt: new Date()
    });

    return true;
  } catch (error) {
    if (error.code === 11000) {
      return false;
    }

    throw error;
  }
}

