function generateTraceId() {
  return crypto.randomUUID();
}

function generateEventId() {
  return crypto.randomUUID();
}

function sanitizeAuditPayload(payload = {}) {
  if (!payload || typeof payload !== "object") {
    return payload;
  }

  try {
    const cloned = JSON.parse(JSON.stringify(payload));

    function walk(obj) {
      if (!obj || typeof obj !== "object") return;

      for (const key of Object.keys(obj)) {
        const value = obj[key];
        const lowerKey = String(key).toLowerCase();

        if (lowerKey === "cpf" && typeof value === "string") {
          obj[key] = maskCPF(value);
        } else if (
          (lowerKey === "telefone" ||
           lowerKey === "telefonewhatsapp" ||
           lowerKey === "user" ||
           lowerKey === "phone") &&
          typeof value === "string"
        ) {
          obj[key] = maskPhone(value);
        } else if (
          lowerKey.includes("password") ||
          lowerKey.includes("token") ||
          lowerKey.includes("apikey") ||
          lowerKey.includes("api_key") ||
          lowerKey.includes("secret")
        ) {
          obj[key] = "[REDACTED]";
        } else if (typeof value === "object") {
          walk(value);
        }
      }
    }

    walk(cloned);
    return cloned;
  } catch (error) {
    return { sanitize_error: error.message };
  }
}

function estimateTokens(text = "") {
  const t = String(text || "");
  if (!t) return 0;
  return Math.ceil(t.length / 4);
}

async function recordAuditEvent({
  traceId = null,
  component = "unknown",
  eventType = "unknown",
  payload = {},
  requiredLevel = "STANDARD",
  parentEventId = null,
  userPhone = "",
  severity = "low"
} = {}) {
  if (!shouldAuditAtLevel(requiredLevel)) {
    return null;
  }

  try {
    await connectMongo();

    const event = {
      _id: generateEventId(),
      traceId: traceId || generateTraceId(),
      parentEventId: parentEventId || null,
      timestamp: new Date(),
      component,
      eventType,
      severity,
      auditLevel: getCurrentAuditLevel(),
      appVersion: APP_VERSION,
      userMasked: userPhone ? maskPhone(userPhone) : "",
      payload: sanitizeAuditPayload(payload),
      createdAt: new Date()
    };

    db.collection("audit_events")
      .insertOne(event)
      .catch(error => {
        console.error("⚠️ Falha ao gravar evento de auditoria (não-crítico):", error.message);
      });

    if (shouldAuditAtLevel("DEEP")) {
      try {
        console.log(
          `📊 [${component}/${eventType}] trace=${event.traceId.slice(0, 8)}`,
          JSON.stringify(event.payload).slice(0, 500)
        );
      } catch (e) {
        // Ignora falha de log
      }
    }

    return event._id;
  } catch (error) {
    console.error("⚠️ Erro no recordAuditEvent (não-crítico):", error.message);
    return null;
  }
}

/*
  ===========================================================
  auditSystemEvent — registra eventos OPERACIONAIS no MongoDB
  ===========================================================
  Diferente do recordAuditEvent (que registra GPTs e webhook),
  esta função grava eventos do BACKEND que antes só apareciam
  no console do Render e se perdiam.

  Categorias:
    - "erro_sistema"      → falha de função, API, GPT
    - "ciclo_followup"    → avanço de step, encerramento, bootstrap
    - "auto_perda"        → lead marcado como perdido e por quê
    - "decisao_taxa"      → aceite, objeção, condicionamento, recusa
    - "mudanca_fase"      → transição de fase do lead (morno→qualificando etc)
    - "decisao_backend"   → orientações estratégicas e travas do backend
    - "rota_comercial"    → migração homologado↔afiliado
    - "coleta_dados"      → início, progresso e conclusão do pré-cadastro
    - "envio_followup"    → mensagem de cadência efetivamente enviada
    - "evento_geral"      → qualquer outro evento relevante

  Tem try/catch interno — nunca derruba o fluxo principal.
*/
async function auditSystemEvent(categoria, severidade, userPhone, payload = {}) {
  try {
    await connectMongo();

    const userMasked = userPhone
      ? String(userPhone).slice(0, 4) + "*****" + String(userPhone).slice(-2)
      : "-";

    await db.collection("audit_events").insertOne({
      traceId: payload.traceId || `sistema_${categoria}_${Date.now()}`,
      component: "backend_sistema",
      eventType: categoria,
      severity: severidade || "low",
      userPhone: userPhone || null,
      userMasked: userMasked,
      timestamp: new Date(),
      payload: payload || {}
    });
  } catch (error) {
    // Nunca derruba o fluxo — apenas loga.
    console.error("⚠️ Erro no auditSystemEvent (não-crítico):", error.message);
  }
}

async function recordRequestCompleted({
  traceId = null,
  userPhone = "",
  mensagemLead = "",
  respostaFinal = "",
  currentLead = {},
  actions = [],
  sdrReviewFindings = [],
  turnPolicy = {},
  extras = {}
} = {}) {
  try {
    await recordAuditEvent({
      traceId,
      component: AUDIT_COMPONENTS.BACKEND_ORCHESTRATOR,
      eventType: AUDIT_EVENT_TYPES.REQUEST_COMPLETED,
      payload: {
        respostaFinalSdr: String(respostaFinal || "").slice(0, 1500),
        actions: Array.isArray(actions) ? actions : [],
        sdrReviewFindingsCount: Array.isArray(sdrReviewFindings) ? sdrReviewFindings.length : 0,
        
         sdrReviewFindings: Array.isArray(sdrReviewFindings)
          ? sdrReviewFindings.slice(0, 5).map(f => {
              const motivoTexto = (() => {
                if (typeof f.motivo === "string" && f.motivo.trim()) return f.motivo.trim();
                if (typeof f.reason === "string" && f.reason.trim()) return f.reason.trim();
                if (f.reason && typeof f.reason === "object") {
                  try { return JSON.stringify(f.reason).slice(0, 500); }
                  catch (_) { return ""; }
                }
                return "";
              })();

              return {
                tipo: f.tipo,
                prioridade: f.prioridade,
                motivo: motivoTexto,
                orientacao: String(f.orientacao || "").slice(0, 800),
                detalhes: f.reason && typeof f.reason === "object" ? f.reason : undefined
              };
            })
          : [],
         
        estadoLead: {
          status: currentLead?.status || "-",
          faseQualificacao: currentLead?.faseQualificacao || "-",
          faseFunil: currentLead?.faseFunil || "-",
          temperaturaComercial: currentLead?.temperaturaComercial || "-",
          rotaComercial: currentLead?.rotaComercial || "-",
          interesseReal: currentLead?.interesseReal === true,
          taxaAlinhada: currentLead?.taxaAlinhada === true,
          taxaObjectionCount: Number(currentLead?.taxaObjectionCount || 0),
          etapas: currentLead?.etapas || {},
          nome: currentLead?.nome ? "[PREENCHIDO]" : "",
          cpf: currentLead?.cpf ? "[PREENCHIDO]" : "",
          telefone: currentLead?.telefone ? "[PREENCHIDO]" : "",
          cidade: currentLead?.cidade || "",
          estado: currentLead?.estado || ""
        },
        turnPolicy: turnPolicy ? {
          modo: turnPolicy.modo || "-",
          ofertaPermitida: turnPolicy.ofertaPermitida || "-",
          podeFalarTaxa: turnPolicy.podeFalarTaxa === true,
          podePedirDados: turnPolicy.podePedirDados === true,
          podeFalarAfiliado: turnPolicy.podeFalarAfiliado === true
        } : null,
        ...extras
      },
      requiredLevel: "STANDARD",
      userPhone,
      severity: (Array.isArray(sdrReviewFindings) && sdrReviewFindings.length > 0) ? "medium" : "low"
    });
  } catch (error) {
    console.error("⚠️ Falha ao gravar request_completed (não-crítico):", error.message);
  }
}

async function recordAuditError({
  traceId = null,
  component = "unknown",
  eventType = "request_failed",
  error = null,
  payload = {},
  userPhone = ""
} = {}) {
  if (!isAuditEnabled()) {
    return null;
  }

  const errorPayload = {
    ...payload,
    error: {
      message: error?.message || String(error),
      stack: error?.stack ? String(error.stack).slice(0, 2000) : "",
      name: error?.name || "Error"
    }
  };

  return recordAuditEvent({
    traceId,
    component,
    eventType,
    payload: errorPayload,
    requiredLevel: "BASIC",
    severity: "high",
    userPhone
  });
}

