    t.includes("valor dos produtos") ||
    t.includes("valores dos produtos") ||
    t.includes("tabela do parceiro") ||
    t.includes("tabela de revenda") ||
    t.includes("preco para parceiro") ||
    t.includes("precos para parceiro")
