    "deixa pra la",
    "deixa pra lá",
    "deixa para la",
    "deixa para lá",
    "vamos deixar",
    "melhor deixar",
    "melhor deixar assim",
    "pode deixar",
    "fica assim",
    "fica pra proxima",
    "fica pra próxima",
    "fica para proxima",
    "fica para próxima",
    "fica para depois",
    "fica pra depois",

    // pedido de encerramento
    "encerra",
    "pode encerrar",
    "pode finalizar",
    "finaliza",
    "finalizar",
    "cancela",
    "cancelar",
    "pode cancelar",
    "encerra ai",
    "encerra aí",
    "fecha ai",
    "fecha aí",
    "fecha por enquanto",

    // adiamento / esfriamento
    "vou pensar",
    "vou analisar",
    "vou avaliar",
    "vou ver depois",
    "vejo depois",
    "talvez depois",
    "mais pra frente",
    "mais para frente",
    "outro momento",
    "outra hora",
    "agora nao",
    "agora não",
    "agora nao da",
    "agora não dá",
    "nao posso agora",
    "não posso agora",
    "nao consigo agora",
    "não consigo agora",

    // preço / taxa / dinheiro
    "achei caro",
    "muito caro",
    "caro demais",
    "taxa alta",
    "valor alto",
    "achei alto",
    "muito alto",
    "ficou pesado",
    "pesado pra mim",
    "pesado para mim",
    "nao tenho dinheiro",
    "não tenho dinheiro",
    "sem dinheiro",
    "sem dinheiro agora",
    "nao tenho esse valor",
    "não tenho esse valor",
    "nao consigo pagar",
    "não consigo pagar",
    "nao posso pagar",
    "não posso pagar",

    // rejeição do modelo
    "nao quero estoque",
    "não quero estoque",
