// ============================================================
// 🔍 DIAGNÓSTICO TEMPORÁRIO — Estado da cadência dos leads mornos
// Adicionado em 2026-05-24 para subsidiar F5.5 (Cadência reaquecimento).
// REMOVER junto com cleanup das outras rotas diagnósticas temporárias.
// ============================================================
app.get("/diagnostico-cadencia-mornos", async (req, res) => {
  if (!requireDashboardAuth(req, res)) return;

  try {
    await connectMongo();

    // Replicação local de getVisualStatus (cópia verbatim do dashboard ~32910).
    // Garante bater EXATAMENTE os mornos que o dashboard conta.
    function getVisualStatusLocal(lead) {
      const dashboard = lead.statusDashboard || lead.statusVisualDashboard || "";
      const fase = lead.faseQualificacao || "";
      const status = lead.status || "";
      const etapas = lead.etapas || {};
      const etapasConcluidas = [etapas.programa, etapas.beneficios, etapas.estoque, etapas.responsabilidades, etapas.investimento].filter(Boolean).length;

      // Terminais autoritativos primeiro (superam dashboard stale — Bug fantasma)
      if (["perdido", "fechado", "negociado", "em_atendimento"].includes(status)) return status;
      if (["perdido", "fechado", "negociado", "em_atendimento"].includes(fase)) return fase;
      // Dashboard só prevalece em estados não-terminais
      if (dashboard && dashboard !== "novo" && dashboard !== "inicio") return dashboard;

      if (["coletando_dados", "dados_parciais", "aguardando_dados", "aguardando_confirmacao_campo", "aguardando_confirmacao_dados"].includes(fase)) return "pre_analise";

      if (["dados_confirmados", "enviado_crm"].includes(fase)) return "quente";

      if (fase === "qualificando") return "qualificando";

      if (etapasConcluidas >= 3) return "qualificando";

      if (fase === "morno" || fase === "afiliado") return "morno";
      if (etapasConcluidas >= 1) return "morno";
      if (status === "morno") return "morno";

      return status || "novo";
    }

    // Bucketização de cadência (prioridade: pausada > ativa > encerrada > nunca_rodou).
    function bucketCadencia(lead) {
      if (lead.cadenciaPausadaPorCliente === true) return "pausada";
      if (lead.proximoFollowupEm !== null && lead.proximoFollowupEm !== undefined) return "ativa";
      if ((lead.followupStep || 0) > 0) return "encerrada";
      return "nunca_rodou";
    }

    function diasParado(lead) {
      const ref = lead.updatedAt || lead.createdAt;
      if (!ref) return null;
      const refDate = ref instanceof Date ? ref : new Date(ref);
      return (Date.now() - refDate.getTime()) / 86400000;
    }

    function userMascarado(user) {
      const s = String(user || "");
      if (s.length <= 8) return s.replace(/.(?=.{2})/g, "*");
      return s.substring(0, 6) + "***" + s.substring(s.length - 2);
    }

    function etapasConcluidasCount(lead) {
      const e = lead.etapas || {};
      return [e.programa, e.beneficios, e.estoque, e.responsabilidades, e.investimento].filter(Boolean).length;
    }

    const allLeads = await db.collection("leads").find({}).toArray();
    const mornos = allLeads.filter(l => getVisualStatusLocal(l) === "morno");

    // Totais gerais
    const totaisGerais = {
      totalMornos: mornos.length,
      porBucket: { pausada: 0, ativa: 0, encerrada: 0, nunca_rodou: 0 },
      diasParado: { media: 0, min: Infinity, max: 0 },
      followupStepDistribution: {}
    };

    const diasParadoArr = [];
    for (const lead of mornos) {
      const bucket = bucketCadencia(lead);
      totaisGerais.porBucket[bucket]++;

      const d = diasParado(lead);
      if (d !== null) {
        diasParadoArr.push(d);
        if (d < totaisGerais.diasParado.min) totaisGerais.diasParado.min = d;
        if (d > totaisGerais.diasParado.max) totaisGerais.diasParado.max = d;
      }

      const step = lead.followupStep || 0;
      totaisGerais.followupStepDistribution[step] = (totaisGerais.followupStepDistribution[step] || 0) + 1;
    }
    totaisGerais.diasParado.media = diasParadoArr.length > 0
      ? diasParadoArr.reduce((a, b) => a + b, 0) / diasParadoArr.length
      : 0;
    if (totaisGerais.diasParado.min === Infinity) totaisGerais.diasParado.min = 0;

    // Distribuição cruzada (bucket × followupStep × faseQualificacao)
    const distribuicao = {};
    for (const lead of mornos) {
      const key = JSON.stringify({
        bucket: bucketCadencia(lead),
        followupStep: lead.followupStep || 0,
        faseQualificacao: lead.faseQualificacao || "N/A"
      });
      if (!distribuicao[key]) {
        distribuicao[key] = { ...JSON.parse(key), count: 0, diasMedio: 0, _soma: 0, _n: 0 };
      }
      distribuicao[key].count++;
      const d = diasParado(lead);
      if (d !== null) {
        distribuicao[key]._soma += d;
        distribuicao[key]._n++;
      }
    }
    const distribuicaoArr = Object.values(distribuicao).map(g => {
      const out = { ...g };
      out.diasMedio = g._n > 0 ? g._soma / g._n : 0;
      delete out._soma;
      delete out._n;
      return out;
    }).sort((a, b) => b.count - a.count);

    // Amostra qualitativa de 10 leads (auditoria getVisualStatus + mensagens reais)
    const amostraIdx = [];
    const total = mornos.length;
    if (total > 0) {
      const passo = Math.max(1, Math.floor(total / 10));
      for (let i = 0; i < 10 && i * passo < total; i++) {
        amostraIdx.push(i * passo);
      }
    }
    const amostra = await Promise.all(amostraIdx.map(async idx => {
      const lead = mornos[idx];

      const etapas = lead.etapas || {};
      const camposClassificacao = {
        statusDashboard: lead.statusDashboard || null,
        statusVisualDashboard: lead.statusVisualDashboard || null,
        faseQualificacao: lead.faseQualificacao || null,
        status: lead.status || null,
        etapas: {
          programa: !!etapas.programa,
          beneficios: !!etapas.beneficios,
          estoque: !!etapas.estoque,
          responsabilidades: !!etapas.responsabilidades,
          investimento: !!etapas.investimento
        },
        etapasConcluidas: etapasConcluidasCount(lead)
      };

      let ultimasMensagens;
      try {
        const historico = await loadConversation(lead.user);
        ultimasMensagens = Array.isArray(historico)
          ? historico.slice(-5).map(m => ({
              role: m.role || "?",
              content: typeof m.content === "string" ? m.content.substring(0, 200) : "<não-texto>",
              createdAt: m.createdAt || null
            }))
          : [];
      } catch (e) {
        ultimasMensagens = "<erro_ao_carregar_conversa>";
      }

      return {
        userMascarado: userMascarado(lead.user),
        statusVisualCalculado: getVisualStatusLocal(lead),
        camposClassificacao,
        cadencia: {
          bucket: bucketCadencia(lead),
          followupStep: lead.followupStep || 0,
          proximoFollowupEm: lead.proximoFollowupEm || null,
          cadenciaPausadaPorCliente: lead.cadenciaPausadaPorCliente === true,
          cadenciaPausadaMotivo: lead.cadenciaPausadaMotivo || null
        },
        diasParado: diasParado(lead),
        createdAt: lead.createdAt || null,
        updatedAt: lead.updatedAt || null,
        ultimasMensagens
      };
    }));

    return res.json({
      timestamp: new Date().toISOString(),
      objetivo: "Subsidiar F5.5 (Cadência reaquecimento PNL) com dados reais dos mornos. Inclui auditoria do getVisualStatus (campos crus na amostra) e últimas mensagens (validação qualitativa).",
      base: {
        totalLeadsBanco: allLeads.length,
        totalMornos: mornos.length
      },
      totaisGerais,
      distribuicaoBucketStepFase: distribuicaoArr,
      amostraQualitativa: amostra
    });
  } catch (error) {
    console.error("[/diagnostico-cadencia-mornos] erro:", error);
    return res.status(500).json({
      ok: false,
      error: error.message,
      stack: error.stack
    });
  }
});

// ============================================================
// F5.5f — Purga retroativa dos mornos (ROTA TEMPORÁRIA)
// Aplica o detector F5.5a (detectLeadIntentFromHistory) retroativamente
// aos leads "morno", encerrando a cadência e marcando perdido com campos
// DISTINTOS do caminho ao vivo (rastreabilidade da purga):
//   - saida_explicita / despedida → envia break-up Afiliado via WhatsApp.
//   - opt_out_explicito → encerra SILENCIOSAMENTE (sem WhatsApp, sem gravar
//     mensagem no histórico). Respeita o opt-out (WhatsApp Business Policy / LGPD).
// Salvaguarda: execução REAL só dentro do horário comercial (reusa
// isBusinessTime — fuso BR, dia útil). dryRun é permitido a qualquer hora.
// Default SEGURO: dryRun=true. Só executa de verdade com ?dryRun=false.
// REMOVER esta rota após a purga única (salvaguarda temporária F5.5f).
// ============================================================
app.get("/admin-purga-mornos-retroativa", async (req, res) => {
  if (!requireDashboardAuth(req, res)) return;

  // Default SEGURO: só aplica alterações com ?dryRun=false explícito.
  const dryRun = String(req.query.dryRun || "true").toLowerCase() !== "false";

  // Salvaguarda F5.5f: execução REAL envia WhatsApp → só em horário comercial.
  const ehHorarioComercial = isBusinessTime();
  if (!dryRun && !ehHorarioComercial) {
    return res.status(200).json({
      ok: false,
      rota: "/admin-purga-mornos-retroativa",
      bloqueado: "fora_do_horario_comercial",
      mensagem: "Execução real bloqueada fora do horário comercial (a purga envia WhatsApp). Rode com dryRun=true para simular, ou aguarde o horário comercial.",
      timestamp: new Date().toISOString()
    });
  }

  try {
    await connectMongo();

    // Replicação local de getVisualStatus (verbatim de /diagnostico-cadencia-mornos).
    function getVisualStatusLocal(lead) {
      const dashboard = lead.statusDashboard || lead.statusVisualDashboard || "";
      const fase = lead.faseQualificacao || "";
      const status = lead.status || "";
      const etapas = lead.etapas || {};
      const etapasConcluidas = [etapas.programa, etapas.beneficios, etapas.estoque, etapas.responsabilidades, etapas.investimento].filter(Boolean).length;

      // Terminais autoritativos primeiro (superam dashboard stale — Bug fantasma)
      if (["perdido", "fechado", "negociado", "em_atendimento"].includes(status)) return status;
      if (["perdido", "fechado", "negociado", "em_atendimento"].includes(fase)) return fase;
      // Dashboard só prevalece em estados não-terminais
      if (dashboard && dashboard !== "novo" && dashboard !== "inicio") return dashboard;

      if (["coletando_dados", "dados_parciais", "aguardando_dados", "aguardando_confirmacao_campo", "aguardando_confirmacao_dados"].includes(fase)) return "pre_analise";

      if (["dados_confirmados", "enviado_crm"].includes(fase)) return "quente";

      if (fase === "qualificando") return "qualificando";

      if (etapasConcluidas >= 3) return "qualificando";

      if (fase === "morno" || fase === "afiliado") return "morno";
      if (etapasConcluidas >= 1) return "morno";
      if (status === "morno") return "morno";

      return status || "novo";
    }

    function userMascarado(user) {
      const s = String(user || "");
      if (s.length <= 8) return s.replace(/.(?=.{2})/g, "*");
      return s.substring(0, 6) + "***" + s.substring(s.length - 2);
    }

    const allLeads = await db.collection("leads").find({}).toArray();
    const mornos = allLeads.filter(l => getVisualStatusLocal(l) === "morno");

    const resumo = {
      totalMornos: mornos.length,
      porIntent: { saida_explicita: 0, opt_out_explicito: 0, aguardar: 0, objecao_linha: 0, sem_intent: 0 },
      elegiveisPurga: 0,
      purgados: 0,
      erros: 0
    };
    const detalhes = [];

    for (const lead of mornos) {
      let history = [];
      try {
        history = await loadConversation(lead.user);
        if (!Array.isArray(history)) history = [];
      } catch (e) {
        resumo.erros++;
        detalhes.push({ userMascarado: userMascarado(lead.user), erro: "loadConversation_falhou" });
        continue;
      }

      const { intentDetectado, acaoIntent, aplicouFiltroTemporal } = detectLeadIntentFromHistory(history);

      const intentKey = intentDetectado || "sem_intent";
      if (resumo.porIntent[intentKey] !== undefined) resumo.porIntent[intentKey]++;

      // Só purga quem sinalizou SAÍDA (break-up): saida_explicita / opt_out_explicito.
      // aguardar/objecao_linha NÃO são saídas → não purga (só conta no resumo).
      if (acaoIntent !== "encerrar_com_breakup") continue;

      resumo.elegiveisPurga++;

      const ehOptOut = intentDetectado === "opt_out_explicito";

      const registro = {
        userMascarado: userMascarado(lead.user),
        intentDetectado,
        aplicouFiltroTemporal,
        followupStepAtual: lead.followupStep || 0,
        cadenciaPausadaAntes: lead.cadenciaPausadaPorCliente === true,
        tipoAcao: ehOptOut ? "encerrar_silencioso_opt_out" : "break_up_whatsapp",
        enviaWhatsApp: !ehOptOut,
        acao: dryRun ? "DRY_RUN_nao_aplicado" : "pendente"
      };

      if (!dryRun) {
        try {
          if (ehOptOut) {
            // CAMINHO SILENCIOSO (opt_out_explicito): respeita o opt-out do lead
            // (WhatsApp Business Policy / LGPD). NÃO envia WhatsApp e NÃO grava
            // mensagem no histórico (nada foi enviado). Só encerra + marca perdido.
            await saveLeadProfile(lead.user, {
              proximoFollowupEm: null,
              followupStep: 0,
              cadenciaPausadaPorCliente: true,
              cadenciaPausadaEm: new Date(),
              cadenciaPausadaMotivo: "purga_retroativa_silenciosa_opt_out",
              status: "perdido",
              statusOperacional: "perdido_por_purga_retroativa",
              faseQualificacao: "perdido",
              motivoPerda: "opt_out_explicito_retroativo",
              encerradoPor: "ia_purga_retroativa_f55f_silenciosa"
            });

            try { clearTimers(lead.user); } catch (e) { /* não-crítico */ }

            console.log(`[F5.5f] Purga retroativa — encerramento SILENCIOSO (opt-out) de ${userMascarado(lead.user)}`);
            registro.acao = "encerrar_silencioso_opt_out";
            resumo.purgados++;
          } else {
            // CAMINHO COM ENVIO (saida_explicita / despedida). Mesma ordem do caminho
            // ao vivo: envia → grava histórico → atualiza lead. Se o envio falhar, o
            // catch impede marcar perdido sem mensagem entregue.
            const breakupMsg = buildBreakupAffiliateMessage(lead, "saida_explicita");

            await sendWhatsAppMessage(lead.user, breakupMsg);

            await saveAutomaticFollowupToHistory(lead.user, breakupMsg, {
              step: lead.followupStep || 0,
              origem: "followup_breakup_purga_retroativa"
            });

            await saveLeadProfile(lead.user, {
              proximoFollowupEm: null,
              followupStep: 0,
              cadenciaPausadaPorCliente: true,
              cadenciaPausadaEm: new Date(),
              cadenciaPausadaMotivo: `purga_retroativa_${intentDetectado}`,
              status: "perdido",
              statusOperacional: "perdido_por_purga_retroativa",
              faseQualificacao: "perdido",
              motivoPerda: `${intentDetectado}_retroativo`,
              encerradoPor: "ia_purga_retroativa_f55f"
            });

            try { clearTimers(lead.user); } catch (e) { /* não-crítico */ }

            console.log(`[F5.5f] Purga retroativa — break-up enviado a ${userMascarado(lead.user)} (intent: ${intentDetectado})`);
            registro.acao = "break_up_enviado";
            resumo.purgados++;
          }
        } catch (e) {
          resumo.erros++;
          registro.acao = "erro_ao_purgar";
          registro.erro = e.message;
        }
      }

      detalhes.push(registro);
    }

    return res.json({
      timestamp: new Date().toISOString(),
      rota: "/admin-purga-mornos-retroativa",
      modo: dryRun ? "DRY_RUN (nenhuma alteração aplicada)" : "EXECUÇÃO REAL (alterações aplicadas)",
      observacao: "Purga só atinge mornos com intent de SAÍDA. saida_explicita/despedida: envia break-up Afiliado via WhatsApp + encerra + marca perdido. opt_out_explicito: encerra SILENCIOSAMENTE (sem WhatsApp, respeita opt-out LGPD/WhatsApp Policy) + marca perdido. Campos distintos de rastreabilidade. Salvaguarda: execução real só em horário comercial. Rota TEMPORÁRIA — remover após a purga.",
      resumo,
      detalhes
    });
  } catch (error) {
    console.error("[/admin-purga-mornos-retroativa] erro:", error);
    return res.status(500).json({
      ok: false,
      error: error.message,
      stack: error.stack
    });
  }
});

// ============================================================
// F5.5g — Rota diagnóstica TEMPORÁRIA pós-purga (read-only)
//
// REMOVER junto com outras rotas temporárias no cleanup futuro.
//
// 3 modos via ?modo=:
//   purgados — Lista os leads purgados pela rota F5.5f em 25/05/2026
//              com suas últimas 10 mensagens. Verifica se algum foi
//              mal classificado pelo bug do padraoLinhaProduto.
//   aguardar — Varre mornos procurando frases candidatas a "aguardar"
//              que o regex atual NÃO captura. Quantifica GAP real.
//   lojista  — Varre mornos+perdidos procurando mensagens da SDR onde
//              ela reconheceu perfil lojista. Cruza com status atual
//              pra quantificar Bug 8 ativo.
// ============================================================
app.get("/diagnostico-pos-purga-25-05", async (req, res) => {
  if (!requireDashboardAuth(req, res)) return;

  const modo = String(req.query.modo || "purgados").toLowerCase();

  if (!["purgados", "aguardar", "lojista"].includes(modo)) {
    return res.status(400).json({
      erro: "modo inválido",
      modosValidos: ["purgados", "aguardar", "lojista"],
      uso: "?senha=...&modo=purgados|aguardar|lojista"
    });
  }

  try {
    await connectMongo();

    function userMascarado(user) {
      const s = String(user || "");
      if (s.length <= 8) return s.replace(/.(?=.{2})/g, "*");
      return s.substring(0, 6) + "***" + s.substring(s.length - 2);
    }

    // ============================================================
    // MODO: purgados
    // ============================================================
    if (modo === "purgados") {
      const purgados = await db.collection("leads").find({
        statusOperacional: "perdido_por_purga_retroativa"
      }).toArray();

      const detalhes = [];
      for (const lead of purgados) {
        const conversation = await loadConversation(lead.user);
        const history = conversation || [];

        const ultimas = history.slice(-10).map(m => ({
          role: m.role,
          content: String(m.content || "").substring(0, 300),
          createdAt: m.createdAt || null
        }));

        const lastUserMsg = [...history].reverse().find(m => m.role === "user");

        detalhes.push({
          userMascarado: userMascarado(lead.user),
          motivoPerda: lead.motivoPerda || null,
          encerradoPor: lead.encerradoPor || null,
          cadenciaPausadaMotivo: lead.cadenciaPausadaMotivo || null,
          cadenciaPausadaEm: lead.cadenciaPausadaEm || null,
          ultimaMsgLeadVerbatim: lastUserMsg
            ? String(lastUserMsg.content || "").substring(0, 400)
            : null,
          ultimaMsgLeadEm: lastUserMsg?.createdAt || null,
          ultimas10MsgsConversa: ultimas
        });
      }

      return res.json({
        timestamp: new Date().toISOString(),
        modo: "purgados",
        totalPurgados: detalhes.length,
        observacao: "Verificar manualmente cada ultimaMsgLeadVerbatim. Se algum lead disse 'não quero piscina' / 'só atendo X' (objeção de linha), foi MAL CLASSIFICADO como saida_explicita pelo bug do padraoLinhaProduto (forense 25/05). Esse lead poderia ter sido pivotado em vez de perdido.",
        detalhes
      });
    }

    // ============================================================
    // MODO: aguardar — GAP do padraoAguardar atual
    // ============================================================
    if (modo === "aguardar") {
      // padraoAguardarAtual: cópia VERBATIM do padraoAguardar real em
      // detectLeadIntentFromHistory @21946 (confirmado na Fase B1 — o
      // template original do spec divergia; substituído pelo regex de produção).
      const padraoAguardarAtual = /\b(vou\s+aguardar|vou\s+esperar|aguardar\s+um\s+pouco|me\s+d[êe]\s+um\s+tempo|depois\s+te\s+falo|depois\s+eu\s+(falo|retorno|respondo)|preciso\s+pensar|deixa\s+eu\s+pensar|vou\s+pensar|pensar\s+mais)\b/i;

      const candidatas = [
        /vou\s+analisar/i,
        /estou\s+analisando/i,
        /\banalisando\b.*\b(volto|retorno|falo)/i,
        /volto\s+a\s+(falar|conversar|chamar)/i,
        /te\s+(chamo|falo|aviso|retorno)\s+depois/i,
        /depois\s+(?:eu\s+)?(?:te\s+)?(?:falo|chamo|aviso)/i,
        /me\s+d[áa]\s+um\s+tempo/i,
        /\bvou\s+ver\b/i,
        /deixa\s+eu\s+ver/i,
        /vou\s+conversar\s+com/i,
        /preciso\s+(?:de\s+)?tempo/i,
        /\bnão\s+(?:é\s+)?(?:agora|hoje)\b/i,
        /talvez\s+(?:mais\s+)?(?:tarde|depois)/i
      ];

      const mornos = await db.collection("leads").find({
        $or: [{ status: "morno" }, { faseQualificacao: "morno" }]
      }).toArray();

      const achados = [];
      const captSummary = {
        totalMornos: mornos.length,
        comFraseCandidata: 0,
        capturadosPeloRegexAtual: 0,
        gapNaoCapturados: 0
      };

      for (const lead of mornos) {
        const conversation = await loadConversation(lead.user);
        const history = conversation || [];
        if (history.length === 0) continue;

        for (const msg of history) {
          if (msg.role !== "user") continue;
          const txt = String(msg.content || "").toLowerCase().trim();

          let matchedRegex = null;
          for (const r of candidatas) {
            if (r.test(txt)) {
              matchedRegex = r.source;
              break;
            }
          }

          if (!matchedRegex) continue;

          captSummary.comFraseCandidata++;
          const capturadoPeloAtual = padraoAguardarAtual.test(txt);
          if (capturadoPeloAtual) captSummary.capturadosPeloRegexAtual++;
          else captSummary.gapNaoCapturados++;

          if (achados.length < 30) {
            achados.push({
              userMascarado: userMascarado(lead.user),
              fraseVerbatim: String(msg.content || "").substring(0, 300),
              regexDiagnosticoQueCasou: matchedRegex,
              regexAtualCapturou: capturadoPeloAtual,
              createdAt: msg.createdAt || null,
              status: lead.status,
              faseQualificacao: lead.faseQualificacao
            });
          }
          break;
        }
      }

      return res.json({
        timestamp: new Date().toISOString(),
        modo: "aguardar",
        resumo: captSummary,
        observacao: 'GAP = leads "morno" com frase candidata que o padraoAguardar atual NÃO capturou. Se gapNaoCapturados > 5, vale ampliar o regex em commit cirúrgico.',
        achados
      });
    }

    // ============================================================
    // MODO: lojista — Bug 8 ativo (SDR detectou mas sistema não atuou)
    // ============================================================
    if (modo === "lojista") {
      const candidatasSdr = [
        /você\s+quer\s+revender/i,
        /quer\s+revender\s+(?:em|na)\s+(?:sua\s+)?loja/i,
        /sua\s+loja/i,
        /\brevender\s+os?\s+produtos?\s+(?:em|na)\s+(?:sua\s+)?loja/i,
        /\blojista\b/i,
        /ponto\s+comercial/i,
        /estabelecimento\s+comercial/i
      ];

      const candidatosBug8 = await db.collection("leads").find({
        $or: [
          { status: "morno" },
          { faseQualificacao: "morno" },
          { status: "perdido" },
          { faseQualificacao: "perdido" }
        ]
      }).toArray();

      const achados = [];
      let totalAnalisados = 0;
      let totalComMencaoSdr = 0;
      let totalBug8Ativo = 0;

      for (const lead of candidatosBug8) {
        totalAnalisados++;
        const conversation = await loadConversation(lead.user);
        const history = conversation || [];
        if (history.length === 0) continue;

        let mencaoSdr = null;
        for (const msg of history) {
          if (msg.role !== "assistant") continue;
          const txt = String(msg.content || "").toLowerCase();

          for (const r of candidatasSdr) {
            if (r.test(txt)) {
              mencaoSdr = {
                regex: r.source,
                trechoVerbatim: String(msg.content || "").substring(0, 400),
                createdAt: msg.createdAt || null
              };
              break;
            }
          }
          if (mencaoSdr) break;
        }

        if (!mencaoSdr) continue;
        totalComMencaoSdr++;

        const fezHandoffHumano = (
          lead.status === "em_atendimento" ||
          lead.faseQualificacao === "em_atendimento" ||
          lead.perfilHandoff === "lojista" ||
          lead.statusOperacional === "humano_atendendo"
        );

        if (!fezHandoffHumano) totalBug8Ativo++;

        if (achados.length < 30) {
          achados.push({
            userMascarado: userMascarado(lead.user),
            sdrDetectouVia: mencaoSdr.regex,
            trechoSdrVerbatim: mencaoSdr.trechoVerbatim,
            quandoSdrDetectou: mencaoSdr.createdAt,
            statusAtual: lead.status,
            faseQualificacaoAtual: lead.faseQualificacao,
            statusOperacionalAtual: lead.statusOperacional || null,
            perfilHandoff: lead.perfilHandoff || null,
            sistemaFezHandoff: fezHandoffHumano,
            bug8Ativo: !fezHandoffHumano
          });
        }
      }

      return res.json({
        timestamp: new Date().toISOString(),
        modo: "lojista",
        resumo: {
          totalAnalisados,
          totalComMencaoSdrSugerindoLojista: totalComMencaoSdr,
          totalBug8Ativo,
          taxaBug8: totalAnalisados > 0
            ? `${((totalBug8Ativo / totalAnalisados) * 100).toFixed(1)}%`
            : "0%"
        },
        observacao: "Bug 8 ativo = leads onde a SDR escreveu mensagem sugerindo perfil lojista MAS o sistema não fez handoff humano. Se totalBug8Ativo > 5, justifica fix prioritário do detector.",
        achados
      });
    }

    return res.status(500).json({ erro: "modo não processado" });
  } catch (error) {
    console.error("[/diagnostico-pos-purga-25-05] erro:", error);
    return res.status(500).json({
      ok: false,
      modo,
      error: error.message,
      stack: error.stack
    });
  }
});

const PORT = process.env.PORT || 3000;

// =====================================================
// DIAGNÓSTICO BUG #1 — ENDPOINT TEMPORÁRIO
// Adicionado: 2026-05-29 para investigar enforceNoBordaoFechamento
// REMOVER APÓS COLETA DE EVIDÊNCIAS
// =====================================================
app.get("/diagnostico-bug-1", async (req, res) => {
  const secret = req.query.secret;
  const EXPECTED_SECRET = process.env.DIAG_SECRET || "iqg-diag-bug1-2026-05-29";
  if (secret !== EXPECTED_SECRET) {
    return res.status(403).json({ error: "forbidden" });
  }

  const report = {
    generatedAt: new Date().toISOString(),
    bug1_paradox_resolution: {},
    counters_state: {},
    process: {},
    render_env: {},
    recent_failures_last_60min: null,
    lead_state_checks: {},
    volume_leads_last_5_days: null,
    errors: []
  };

  // ============ FASE 1: ARQUIVO server.js DEPLOYADO ============
  try {
    const fs = await import("fs");
    const path = await import("path");
    const serverPath = path.resolve("server.js");

    let fileContent = "";
    let fileLines = 0;
    let fileSize = 0;
    try {
      fileContent = fs.readFileSync(serverPath, "utf-8");
      fileLines = fileContent.split("\n").length;
      fileSize = fs.statSync(serverPath).size;
    } catch (e) {
      report.errors.push({ phase: "fs_read", error: e.message });
    }

    // Procurar declarações e chamadas da função
    const defRegex = /function\s+enforceNoBordaoFechamento\s*\(/g;
    const callRegex = /enforceNoBordaoFechamento\s*\(/g;
    const defMatches = [];
    const callMatches = [];
    let m;
    while ((m = defRegex.exec(fileContent)) !== null) {
      const lineNumber = fileContent.substring(0, m.index).split("\n").length;
      defMatches.push({ line: lineNumber, snippet: fileContent.substring(m.index, m.index + 80) });
    }
    callRegex.lastIndex = 0;
    while ((m = callRegex.exec(fileContent)) !== null) {
      const lineNumber = fileContent.substring(0, m.index).split("\n").length;
      const isDef = defMatches.some(d => Math.abs(d.line - lineNumber) <= 1);
      if (!isDef) {
        callMatches.push({ line: lineNumber, snippet: fileContent.substring(m.index, m.index + 100) });
      }
    }

    report.bug1_paradox_resolution.file = {
      path: serverPath,
      lines: fileLines,
      size_bytes: fileSize
    };
    report.bug1_paradox_resolution.enforceNoBordaoFechamento_in_file = {
      definitions_found: defMatches,
      calls_found: callMatches,
      definitions_count: defMatches.length,
      calls_count: callMatches.length
    };
  } catch (e) {
    report.errors.push({ phase: "phase1_file_read", error: e.message });
  }

  // ============ FASE 2: TYPEOF RUNTIME ============
  try {
    const runtimeFunctions = {};
    const candidates = [
      "enforceNoBordaoFechamento",
      "enforceNoFichouAlgumaDuvida",
      "enforceClarityCheckAfterExplanation",
      "enforceNoSePrecisarNoQualquerDuvida",
      "sendAutomaticFollowupIfStillValid",
      "markStep",
      "saveLeadProfile",
      "runFollowupCronTick",
      "iqgBuildFunnelProgressUpdateFromLeadReply",
      "auditSystemEvent"
    ];
    for (const fname of candidates) {
      try {
        runtimeFunctions[fname] = eval(`typeof ${fname}`);
      } catch (e) {
        runtimeFunctions[fname] = `EVAL_ERROR: ${e.message}`;
      }
    }
    report.bug1_paradox_resolution.runtime_typeof = runtimeFunctions;
  } catch (e) {
    report.errors.push({ phase: "phase2_typeof", error: e.message });
  }

  // ============ FASE 3: TRY-CALL enforceNoBordaoFechamento ============
  try {
    const testInput = "Mensagem teste. Fico à disposição.";
    let callResult;
    try {
      const result = eval("enforceNoBordaoFechamento")(testInput);
      callResult = {
        success: true,
        inputLength: testInput.length,
        outputLength: result?.length,
        outputDiffers: result !== testInput,
        outputPreview: typeof result === "string" ? result.substring(0, 120) : String(result)
      };
    } catch (e) {
      callResult = {
        success: false,
        errorName: e.name,
        errorMessage: e.message,
        stackPreview: e.stack ? e.stack.substring(0, 500) : null
      };
    }
    report.bug1_paradox_resolution.try_call_enforceNoBordaoFechamento = callResult;
  } catch (e) {
    report.errors.push({ phase: "phase3_trycall", error: e.message });
  }

  // ============ FASE 4: COUNTERS STATE ============
  try {
    try {
      const gc = eval("F8GAMMA2_COUNTERS");
      report.counters_state.F8GAMMA2_COUNTERS = JSON.parse(JSON.stringify(gc));
    } catch (e) {
      report.counters_state.F8GAMMA2_COUNTERS = `ERROR: ${e.message}`;
    }
    try {
      const f75 = eval("F75_SUBSTITUTO_COUNTER");
      report.counters_state.F75_SUBSTITUTO_COUNTER = f75;
    } catch (e) {
      report.counters_state.F75_SUBSTITUTO_COUNTER = `ERROR: ${e.message}`;
    }
  } catch (e) {
    report.errors.push({ phase: "phase4_counters", error: e.message });
  }

  // ============ FASE 5: PROCESS INFO ============
  try {
    const up = process.uptime();
    report.process = {
      pid: process.pid,
      cwd: process.cwd(),
      uptime_seconds: Math.round(up),
      uptime_human: `${Math.floor(up / 3600)}h ${Math.floor((up % 3600) / 60)}m`,
      node_version: process.version,
      platform: process.platform,
      heapUsed_mb: Math.round(process.memoryUsage().heapUsed / 1024 / 1024),
      rss_mb: Math.round(process.memoryUsage().rss / 1024 / 1024)
    };
  } catch (e) {
    report.errors.push({ phase: "phase5_process", error: e.message });
  }

  // ============ FASE 6: RENDER ENV ============
  try {
    report.render_env = {
      RENDER: process.env.RENDER,
      RENDER_SERVICE_ID: process.env.RENDER_SERVICE_ID,
      RENDER_GIT_COMMIT: process.env.RENDER_GIT_COMMIT,
      RENDER_GIT_BRANCH: process.env.RENDER_GIT_BRANCH,
      RENDER_INSTANCE_ID: process.env.RENDER_INSTANCE_ID,
      RENDER_EXTERNAL_HOSTNAME: process.env.RENDER_EXTERNAL_HOSTNAME
    };
  } catch (e) {
    report.errors.push({ phase: "phase6_renderenv", error: e.message });
  }

  // ============ FASE 7: AUDIT EVENTS RECENTES ============
  try {
    await connectMongo();
    const failures = await db.collection("audit_events").find({
      eventType: { $in: ["followup_failed", "erro_sistema", "supervisor_abortado", "regeneracao_sdr_tentativa_falha"] },
      timestamp: { $gte: new Date(Date.now() - 60 * 60 * 1000) }
    }).sort({ timestamp: -1 }).limit(20).toArray();
    report.recent_failures_last_60min = failures.map(f => ({
      eventType: f.eventType,
      severity: f.severity,
      timestamp: f.timestamp,
      userPhone: f.userPhone,
      payload: f.payload
    }));
  } catch (e) {
    report.errors.push({ phase: "phase7_audit", error: e.message });
    report.recent_failures_last_60min = { error: e.message };
  }

  // ============ FASE 8: LEAD STATE CHECKS ============
  try {
    await connectMongo();
    const leadsToCheck = {
      Harrykeim: "555196.*96$",
      João: "551999.*68$",
      Ulisses: "555182.*11$",
      JCardoso: "558591.*66$"
    };
    for (const [name, pattern] of Object.entries(leadsToCheck)) {
      try {
        const lead = await db.collection("leads").findOne(
          { user: { $regex: new RegExp(pattern) } },
          { projection: { user: 1, etapas: 1, faseFunil: 1, status: 1, updatedAt: 1, createdAt: 1, _id: 0 } }
        );
        report.lead_state_checks[name] = lead || "NOT_FOUND";
      } catch (e) {
        report.lead_state_checks[name] = { error: e.message };
      }
    }
  } catch (e) {
    report.errors.push({ phase: "phase8_leads", error: e.message });
  }

  // ============ FASE 9: VOLUME LEADS/DIA ============
  try {
    await connectMongo();
    const fiveDaysAgo = new Date(Date.now() - 5 * 24 * 60 * 60 * 1000);
    const volumeAgg = await db.collection("leads").aggregate([
      { $match: { createdAt: { $gte: fiveDaysAgo } } },
      { $group: {
          _id: { $dateToString: { format: "%Y-%m-%d", date: "$createdAt" } },
          count: { $sum: 1 }
      }},
      { $sort: { _id: 1 } }
    ]).toArray();
    report.volume_leads_last_5_days = volumeAgg;
  } catch (e) {
    report.errors.push({ phase: "phase9_volume", error: e.message });
    report.volume_leads_last_5_days = { error: e.message };
  }

  // ============ FASE 10: VALIDACAO_FOLLOWUPS + STEP FINAL + RISCO BAN ============
  try {
    await connectMongo();

    // Detectores
    const REGEX_DESPEDIDA = /(foi um prazer|agradeço o interesse|agradeço seu interesse|tudo de bom|tudo certo|boa sorte|sucesso|um abraço|abraços|até (mais|breve|logo|qualquer hora))/i;
    const REGEX_DISPONIBILIDADE = /(estou (à|a) (disposição|sua disposição)|se precisar (de )?(algo|ajuda|mais)|qualquer (coisa|dúvida)|fico (à|a) (disposição|sua disposição)|aqui se precisar|se quiser (é só |me )?(me )?(chamar|chame|falar|avisar)|conta comigo|tô (por )?aqui)/i;
    // P.7: URL afiliado descoberto = minhaiqg.com.br
    const REGEX_AFILIADO = /(afiliado|programa de afiliados|link de afiliado|minhaiqg\.com\.br|loja virtual|loja online|e.commerce|catalog[oó] online|catalogo digital|comissão por venda|comprar pelo (site|app)|nossa loja online|nosso e.commerce)/i;

    // Janela: maior entre uptime atual e últimos 120min
    const processStart = new Date(Date.now() - process.uptime() * 1000);
    const twoHoursAgo = new Date(Date.now() - 120 * 60 * 1000);
    const sinceWindow = processStart > twoHoursAgo ? processStart : twoHoursAgo;

    // P.3: emite envio_followup (texto truncado 300) + followup_sent (texto full em respostaFinalSdr)
    // P.4: payload tem step, closeAfter, respostaFinalSdr (full), mensagem (trunc), faseFunil, faseQualificacao, status
    const followups = await db.collection("audit_events").find({
      eventType: { $in: ["envio_followup", "ciclo_followup", "followup_sent"] },
      timestamp: { $gte: sinceWindow }
    }).sort({ timestamp: 1 }).limit(60).toArray();

    const validations = [];
    let step5Total = 0;
    let step5Compliant = 0;
    const highRiskLeads = [];

    for (const fup of followups) {
      const phone = fup.userPhone;
      if (!phone) continue;

      // Lead state
      let lead = null;
      try {
        lead = await db.collection("leads").findOne(
          { user: phone },
          { projection: { user: 1, faseFunil: 1, etapas: 1, updatedAt: 1, createdAt: 1, status: 1, _id: 0 } }
        );
      } catch (e) { lead = { error: e.message }; }

      // Conversation tail
      // P.6: schema = { role, content, createdAt, origem, followupStep }
      let lastMessages = [];
      let totalSdrMsgs24h = 0;
      let totalSdrMsgsLifetime = 0;
      let consecutiveSdrCount = 0;
      try {
        const conv = await db.collection("conversations").findOne(
          { user: phone },
          { projection: { messages: 1 } }
        );
        if (conv && Array.isArray(conv.messages)) {
          const allMsgs = conv.messages;
          totalSdrMsgsLifetime = allMsgs.filter(m => m.role === "assistant").length;
          const twentyFourHAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
          totalSdrMsgs24h = allMsgs.filter(m =>
            m.role === "assistant" &&
            m.createdAt &&
            new Date(m.createdAt) >= twentyFourHAgo
          ).length;

          // Contar SDR consecutivos no FIM (sem user responder entre eles)
          for (let i = allMsgs.length - 1; i >= 0; i--) {
            if (allMsgs[i].role === "assistant") consecutiveSdrCount++;
            else break;
          }

          lastMessages = allMsgs.slice(-8).map(m => ({
            role: m.role,
            createdAt: m.createdAt,
            preview: typeof m.content === "string" ? m.content.substring(0, 200) : null
          }));
        }
      } catch (e) { lastMessages = { error: e.message }; }

      // Inactivity (last user msg)
      let inactiveForHours = null;
      try {
        if (Array.isArray(lastMessages)) {
          const lastUserMsg = [...lastMessages].reverse().find(m => m.role === "user");
          if (lastUserMsg && lastUserMsg.createdAt) {
            inactiveForHours = Math.round((Date.now() - new Date(lastUserMsg.createdAt).getTime()) / 3600000 * 10) / 10;
          }
        }
      } catch (e) { /* ignore */ }

      // P.3: step + closeAfter identification
      const stepNum = fup.payload?.step ?? null;
      const isCloseAfter = fup.payload?.closeAfter === true || stepNum === 5;

      // P.4: respostaFinalSdr (full) tem prioridade sobre mensagem (truncado 300)
      const msgText = fup.payload?.respostaFinalSdr || fup.payload?.mensagem || fup.payload?.messageText || fup.payload?.message || fup.payload?.text || "";

      // Step 5 compliance
      let step5Check = null;
      if (isCloseAfter) {
        step5Total++;
        const hasDespedida = REGEX_DESPEDIDA.test(msgText);
        const hasDisponibilidade = REGEX_DISPONIBILIDADE.test(msgText);
        const hasAfiliado = REGEX_AFILIADO.test(msgText);
        const allThree = hasDespedida && hasDisponibilidade && hasAfiliado;
        if (allThree) step5Compliant++;
        step5Check = {
          isFinalStep: true,
          despedida: hasDespedida,
          disponibilidade: hasDisponibilidade,
          afiliado: hasAfiliado,
          all_three_present: allThree,
          missing: [
            !hasDespedida && "despedida",
            !hasDisponibilidade && "disponibilidade",
            !hasAfiliado && "afiliado"
          ].filter(Boolean)
        };
      }

      // Risk indicators
      const riskIndicators = {
        total_sdr_msgs_24h: totalSdrMsgs24h,
        total_sdr_msgs_lifetime: totalSdrMsgsLifetime,
        consecutive_sdr_count: consecutiveSdrCount,
        last_lead_msg_age_hours: inactiveForHours,
        ban_risk_level:
          consecutiveSdrCount >= 5 ? "HIGH" :
          consecutiveSdrCount >= 3 ? "MEDIUM" :
          totalSdrMsgs24h >= 5 ? "MEDIUM" : "LOW"
      };

      if (riskIndicators.ban_risk_level === "HIGH" || riskIndicators.ban_risk_level === "MEDIUM") {
        highRiskLeads.push({
          phone: phone,
          consecutive_sdr: consecutiveSdrCount,
          msgs_24h: totalSdrMsgs24h,
          msgs_lifetime: totalSdrMsgsLifetime,
          faseFunil: lead?.faseFunil
        });
      }

      validations.push({
        followup: {
          timestamp: fup.timestamp,
          eventType: fup.eventType,
          step: stepNum,
          is_close_after: isCloseAfter,
          textPreview: msgText.substring(0, 400),
          textLength: msgText.length,
          payloadKeys: Object.keys(fup.payload || {})
        },
        lead: {
          phone: phone,
          faseFunil: lead?.faseFunil || null,
          etapas: lead?.etapas || null,
          status: lead?.status || null,
          updatedAt: lead?.updatedAt || null,
          createdAt: lead?.createdAt || null,
          inactiveForHours: inactiveForHours
        },
        conversation_tail: {
          messages_count: Array.isArray(lastMessages) ? lastMessages.length : null,
          last_8: lastMessages
        },
        step5_compliance: step5Check,
        risk_indicators: riskIndicators
      });
    }

    report.validacao_followups_recentes = {
      windowFrom: sinceWindow.toISOString(),
      processUptimeSeconds: Math.round(process.uptime()),
      totalFollowupsFound: followups.length,
      step5_summary: {
        total_step5: step5Total,
        compliant_with_all_three: step5Compliant,
        compliance_rate: step5Total > 0 ? Math.round(step5Compliant / step5Total * 100) : null
      },
      ban_risk_summary: {
        total_high_or_medium_risk: highRiskLeads.length,
        high_risk_leads: highRiskLeads
      },
      validations: validations
    };
  } catch (e) {
    report.errors.push({ phase: "phase10_followup_validation", error: e.message });
    report.validacao_followups_recentes = { error: e.message };
  }
  // ============ FIM FASE 10 ============

  res.json(report);
});
// =====================================================
// FIM DIAGNÓSTICO BUG #1
// =====================================================

// ====== ENDPOINT TEMPORÁRIO — forense funil conversao (REMOVER apos analise) ======
app.get("/diagnostico-funil-conversao", async (req, res) => {
  if (req.query.senha !== "iqg-funil-2026") {
    return res.status(403).json({ error: "forbidden" });
  }
  try {
    // getVisualStatus CORRIGIDO (terminais primeiro — versao pos-fix 0be303a)
    const getVisualStatus = lead => {
      const dashboard = lead.statusDashboard || lead.statusVisualDashboard || "";
      const fase = lead.faseQualificacao || "";
      const status = lead.status || "";
      const etapas = lead.etapas || {};
      const etapasConcluidas = [etapas.programa, etapas.beneficios, etapas.estoque, etapas.responsabilidades, etapas.investimento].filter(Boolean).length;
      if (["perdido", "fechado", "negociado", "em_atendimento"].includes(status)) return status;
      if (["perdido", "fechado", "negociado", "em_atendimento"].includes(fase)) return fase;
      if (dashboard && dashboard !== "novo" && dashboard !== "inicio") return dashboard;
      if (["coletando_dados", "dados_parciais", "aguardando_dados", "aguardando_confirmacao_campo", "aguardando_confirmacao_dados"].includes(fase)) return "pre_analise";
      if (["dados_confirmados", "enviado_crm"].includes(fase)) return "quente";
      if (fase === "qualificando") return "qualificando";
      if (etapasConcluidas >= 3) return "qualificando";
      if (fase === "morno" || fase === "afiliado") return "morno";
      if (etapasConcluidas >= 1) return "morno";
      if (status === "morno") return "morno";
      return status || "novo";
    };

    // Detectar campo de array de mensagens (nome varia)
    const detectarCampoMsgs = lead => {
      const candidatos = ["mensagens", "historico", "historicoMensagens", "messages", "conversation", "conversa", "chatHistory"];
      for (const c of candidatos) if (Array.isArray(lead[c])) return c;
      return null;
    };

    const leads = await db.collection("leads").find({}).toArray();
    const campoMsgs = leads.length ? detectarCampoMsgs(leads[0]) : null;

    const funilEstagio = {};
    const funilEtapas = { programa: 0, beneficios: 0, estoque: 0, responsabilidades: 0, investimento: 0 };
    const distNumEtapas = {};
    const perdidosPorMotivo = {};
    const perdidosPorStep = {};
    const engajamentoGeral = { "0_nunca_respondeu": 0, "1_msg": 0, "2a4_msgs": 0, "5mais_msgs": 0 };
    const engajamentoPorFase = {};
    let quentesTotal = 0, quentesFechados = 0;

    leads.forEach(lead => {
      const vs = getVisualStatus(lead);
      funilEstagio[vs] = (funilEstagio[vs] || 0) + 1;

      const etapas = lead.etapas || {};
      if (etapas.programa) funilEtapas.programa++;
      if (etapas.beneficios) funilEtapas.beneficios++;
      if (etapas.estoque) funilEtapas.estoque++;
      if (etapas.responsabilidades) funilEtapas.responsabilidades++;
      if (etapas.investimento) funilEtapas.investimento++;
      const n = [etapas.programa, etapas.beneficios, etapas.estoque, etapas.responsabilidades, etapas.investimento].filter(Boolean).length;
      distNumEtapas[n] = (distNumEtapas[n] || 0) + 1;

      if (vs === "perdido") {
        const motivo = lead.motivoPerda || "(sem motivo)";
        perdidosPorMotivo[motivo] = (perdidosPorMotivo[motivo] || 0) + 1;
        const step = (lead.followupStep != null) ? ("step_" + lead.followupStep) : "(sem step)";
        perdidosPorStep[step] = (perdidosPorStep[step] || 0) + 1;
      }

      if (campoMsgs) {
        const arr = lead[campoMsgs] || [];
        const nMsgsLead = arr.filter(m => m && (m.role === "user" || m.origem === "lead" || m.from === "lead")).length;
        let bucket;
        if (nMsgsLead === 0) bucket = "0_nunca_respondeu";
        else if (nMsgsLead === 1) bucket = "1_msg";
        else if (nMsgsLead <= 4) bucket = "2a4_msgs";
        else bucket = "5mais_msgs";
        engajamentoGeral[bucket]++;
        if (!engajamentoPorFase[vs]) engajamentoPorFase[vs] = { "0": 0, "1": 0, "2a4": 0, "5+": 0 };
        if (nMsgsLead === 0) engajamentoPorFase[vs]["0"]++;
        else if (nMsgsLead === 1) engajamentoPorFase[vs]["1"]++;
        else if (nMsgsLead <= 4) engajamentoPorFase[vs]["2a4"]++;
        else engajamentoPorFase[vs]["5+"]++;
      }

      if (vs === "quente") {
        quentesTotal++;
        if (lead.status === "fechado" || lead.status === "negociado") quentesFechados++;
      }
    });

    res.json({
      totalLeads: leads.length,
      campoMensagensDetectado: campoMsgs,
      amostraCamposLead: leads.length ? Object.keys(leads[0]).sort() : [],
      funil_estagio: funilEstagio,
      funil_etapas_acumulado: funilEtapas,
      distribuicao_num_etapas: distNumEtapas,
      perdidos_por_motivo: perdidosPorMotivo,
      perdidos_por_followup_step: perdidosPorStep,
      engajamento_geral: campoMsgs ? engajamentoGeral : "campo de mensagens nao detectado",
      engajamento_por_fase: campoMsgs ? engajamentoPorFase : "campo de mensagens nao detectado",
      quentes: { total: quentesTotal, fechados: quentesFechados }
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});
// ====== fim endpoint temporário forense funil ======

// ====== ENDPOINT TEMPORÁRIO — etapas reais vs apresentadas (REMOVER apos analise) ======
app.get("/diagnostico-etapas-reais", async (req, res) => {
  if (req.query.senha !== "iqg-etapas-2026") return res.status(403).json({ error: "forbidden" });
  try {
    const getVisualStatus = lead => {
      const dashboard = lead.statusDashboard || lead.statusVisualDashboard || "";
      const fase = lead.faseQualificacao || "";
      const status = lead.status || "";
      const etapas = lead.etapas || {};
      const ec = [etapas.programa, etapas.beneficios, etapas.estoque, etapas.responsabilidades, etapas.investimento].filter(Boolean).length;
      if (["perdido","fechado","negociado","em_atendimento"].includes(status)) return status;
      if (["perdido","fechado","negociado","em_atendimento"].includes(fase)) return fase;
      if (dashboard && dashboard !== "novo" && dashboard !== "inicio") return dashboard;
      if (["coletando_dados","dados_parciais","aguardando_dados","aguardando_confirmacao_campo","aguardando_confirmacao_dados"].includes(fase)) return "pre_analise";
      if (["dados_confirmados","enviado_crm"].includes(fase)) return "quente";
      if (fase === "qualificando") return "qualificando";
      if (ec >= 3) return "qualificando";
      if (fase === "morno" || fase === "afiliado") return "morno";
      if (ec >= 1) return "morno";
      if (status === "morno") return "morno";
      return status || "novo";
    };

    const convSample = await db.collection("conversations").findOne({});
    const campoUser = ["user","telefone","from","waId","phone","numero"].find(k => convSample && convSample[k] != null) || "user";
    const campoRole = ["role","origem","sender","direction","tipo"].find(k => convSample && convSample[k] != null && k !== campoUser) || null;
    let msgsLeadPorUser = {};
    const pipe = campoRole
      ? [{ $match: { [campoRole]: { $in: ["user","lead","cliente","inbound","received","in"] } } }, { $group: { _id: "$"+campoUser, total: { $sum: 1 } } }]
      : [{ $group: { _id: "$"+campoUser, total: { $sum: 1 } } }];
    const agg = await db.collection("conversations").aggregate(pipe).toArray();
    agg.forEach(a => { if (a._id != null) msgsLeadPorUser[String(a._id)] = a.total; });

    const ordem = ["programa","beneficios","estoque","responsabilidades","investimento"];
    const idxEtapa = nome => ordem.indexOf(nome);

    const leads = await db.collection("leads").find({}).toArray();
    const zero = { total: 0, responderam: 0, naoResponderam: 0, sdrApresentouAlgo: 0, sdrNaoApresentouNada: 0, comAguardandoEntendimento: 0, distUltimaApresentada: {} };
    let divergenciaApresentadaMaiorQueConcluida = 0;
    const amostra = [];

    leads.forEach(lead => {
      const etapas = lead.etapas || {};
      const ne = ordem.filter(k => etapas[k]).length;
      const ultimaApres = lead.ultimaEtapaApresentadaPelaSdr || "";
      const idxApres = idxEtapa(ultimaApres);
      const numApresentadas = idxApres >= 0 ? idxApres + 1 : 0;
      const msgs = msgsLeadPorUser[String(lead.user)] || 0;
      let ag = lead.etapasAguardandoEntendimento;
      let temAg = Array.isArray(ag) ? ag.length > 0 : (ag && typeof ag === "object" ? Object.keys(ag).length > 0 : !!ag);

      if (numApresentadas > ne) divergenciaApresentadaMaiorQueConcluida++;

      if (ne === 0) {
        zero.total++;
        if (msgs > 0) zero.responderam++; else zero.naoResponderam++;
        if (numApresentadas > 0) zero.sdrApresentouAlgo++; else zero.sdrNaoApresentouNada++;
        if (temAg) zero.comAguardandoEntendimento++;
        const ch = ultimaApres || "(nenhuma)";
        zero.distUltimaApresentada[ch] = (zero.distUltimaApresentada[ch] || 0) + 1;
        if (msgs > 0 && amostra.length < 10) {
          amostra.push({
            user: lead.user, getVisualStatus: getVisualStatus(lead), etapasConcluidas: ne,
            ultimaEtapaApresentadaPelaSdr: ultimaApres || null,
            etapasAguardandoEntendimento: ag || null,
            ultimaEvidenciaEntendimentoFunil: lead.ultimaEvidenciaEntendimentoFunil || null,
            faseQualificacao: lead.faseQualificacao, msgsDoLead: msgs, createdAt: lead.createdAt
          });
        }
      }
    });

    res.json({
      totalLeads: leads.length,
      meta_conversations: { campoUser, campoRole, contandoMsgsDoLead: !!campoRole },
      divergencia_apresentada_vs_concluida: divergenciaApresentadaMaiorQueConcluida,
      zero_etapas_concluidas: zero,
      amostra_zero_que_responderam: amostra
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});
